// volfi_annulus_endpoint_vec.hpp   (GENERATED by generate_endpoint_vec.py)
// ---------------------------------------------------------------------------
// NEW offline constants that VECTORIZE the LEFT and RIGHT endpoint charts of the
// broad-range volfi-annulus inverter.  With these tables the LEFT/RIGHT inner
// loops become pure branchless Clenshaw/rational kernels (NO libm exp/erfc, and
// log only via the reused, already-vectorized log2approx), so the scalar entry
// and every batch driver call the SAME inlines and stay BIT-IDENTICAL, while
// machine precision is preserved.  These SUPPLEMENT volfi_annulus_broadrange.hpp
// (Binv, LEFT finisher, seam curves) -- all of those constants are UNCHANGED.
// WING and the frozen CENTRAL table are untouched.
//
// ==== LEFT reformulated inner-loop recipe (per c; per-h scalars hoisted) ====
//   inv_expm1h, h, h2=h*h, h4=h2*h2, xt = 2*h2/LEFT_T_MAX - 1   [index pass]
//   rho = c * inv_expm1h
//   A   = binv(rho)              // regime a: k/(rho+.5) Cheb15 ; b1/b2: sqrt(Cheb)
//                                // in L = -full_log(rho), full_log(x) =
//                                //   BR_LN2*( exponent(x) + log2approx(mantissa(x)) )
//                                //   (EXISTING log2approx; scalar==SIMD bit-identical)
//   s   = h / A
//   x   = sigma0_poly(BR_K*s)                         // EXISTING erfinv kernel
//   xs  = 2*s/LEFT_S_MAX - 1
//   V2  = cheb1(LEFT_V2_CHEB,29, 0, LEFT_S_CHEB_MAX, s)   // <-- NEW (no exp, no series branch)
//   V4  = cheb1(LEFT_V4_CHEB,27, 0, LEFT_S_CHEB_MAX, s)   // <-- NEW
//   fin = clenshaw2(2,16, LEFT_FIN_COEFFS, xt, xs)        // EXISTING frozen finisher
//   v   = x + h2*V2 + h4*V4 + (h4*h2)*fin ;   w = v*v
//   Only div/sqrt (hardware) + Clenshaw fma loops.  NO exp, NO erfc, NO libm log.
//
// ==== RIGHT reformulated inner-loop recipe (per c; eh=exp(-h/2),ehp=exp(h)
//      precomputed ONCE per h in the scalar index pass, libm, broadcast) ====
//   gbar = 0.5*(1-c)*eh
//   x0   = -qnorm0(gbar)         // Acklam rational (QN_A/B/C/D); tail branch (p<QN_P_LOW)
//                                //   uses full_log = BR_LN2*(exp+log2approx(mant)); rel~1.1e-9
//   m    = SQRT_PI2 * erfcx_poly(x0*IS2)          // Mills EXACT via shared erfcx (NO per-quote table)
//   inv=1/x0; x2=-0.125*(inv-m); x4=0.5*x0*x2^2+0.125*x2*inv^2+((inv^3-inv+m)/3)/128
//   x    = x0 + h2*x2 + h4*x4
//   repeat RIGHT_NEWTON_STEPS (=6) FIXED (no early-exit, no free-zone skip; bit-identity):
//       vv=2x; cmC = (c<0.5)? c-black_otm : onem_otm-(1-c)      // masked select
//       black_otm/onem_otm price via Phi=0.5*erfc_shared, ehp=exp(h) (per-h scalar)
//       erfc_shared(t): a=|t|; e=erfcx_poly(a)*exp_neg(-a*a); (t>=0? e : 2-e)   // masked sign
//       gp = -BR_K*exp_neg(-0.5*x*x)*exp_neg(-h2/(8*x*x))
//       x -= 0.5*cmC*eh/gp
//   v = 2x ;  w = v*v.   NO Newton-with-libm, NO erfc, NO exp in the loop
//   (exp_neg: a in [-30,0]; Cody-Waite reduce a = -n*LN2 + r via (LN2_HI,LN2_LO),
//    r in [-ln2/2,ln2/2]; exp = 2^n * poly(EXP_C, r) using scalef/ldexp).
// ---------------------------------------------------------------------------
