static const double SQRT_PI2 = 1.25331413731550034e+00;   // sqrt(pi/2), Mills scale
// D: warm-start refinement (calibration loops re-inverting a moved surface).
// CONVERGENCE basin (50-digit oracle): 3 fixed HH3 steps converge from seeds off by up to
// +-10% for W<=15, +-5% for W<=30, +-2% for W<=50 (W = h^2/(2 w_prev)); caller guard W<=40.
// ACCURACY floor (measured vs the cold inverter, 6851 mixed-h pts): the (y,r) price
// representation rounds y and r by half an ulp each, which the deep-OTM price cancellation
// amplifies; the warm result is therefore accurate to a FEW ULP rather than the last bit:
// worst 2.9e-15 for W<=8 (any realistically traded quote), growing to ~1.3e-14 at W=40;
// median sub-ulp.  This floor is intrinsic to x-space polishing (the cold wing chart works
// in log-price space precisely to avoid it), so a calibrator wanting last-bit output should
// cold-invert the FINAL iterate; intermediate iterates gain nothing from that precision.
static const int WARM_HH3_STEPS = 3;
// Fast warm path for the live streaming regime (tick-to-tick / F-tick moves, where
// the vol moves sub-percent).  De-risked (2026-07-14, warm-vs-truth over W<=40,
// both move signs): 2 HH3 steps reach the SAME floor as 3 for |dv/v| <= 1% at every
// W; they diverge only for moves >= 2% at deep W (which the guard below catches).
static const int    WARM_HH3_FAST_STEPS = 2;
// Convergence guard: the last HH3 relative correction |dx/x|.  For a converged
// 2-step warm from a <=1% move it is ~1e-8; a move too large for 2 steps leaves it
// >~1e-7.  A caller using warm_variance_fast re-inverts cold when *ok comes back
// false (out-of-basin move), so the fast path never returns a low-accuracy result
// silently.
static const double WARM_FAST_TOL = 1e-6;
static const int    RIGHT_HH3_STEPS = 3;   // FIXED count of Householder-3 (order-4) steps,
                                           // no early-exit.  Replaces the former fixed-6 Newton:
                                           // the closed-form logarithmic derivative of the RIGHT
                                           // equation makes the 2nd/3rd derivatives (a=g''/g',
                                           // b=g'''/g') cheap rationals, so an order-4 step costs
                                           // one Newton step; 3 of them reach machine precision
                                           // with >10 orders of margin from the ladder seed even
                                           // at its worst point (near the wing seam, seed err 0.27).

